parameters.query:
SELECT id, slug, name, manufacturer, category
FROM datap4k_mining_gear_norm
ORDER BY category, name;

parameters.functionCode:
var row = items[0].json;
var catLabels = {
  'mining-laser': 'Mining Laser',
  'mining-module-active': 'Mining Module (Active)',
  'mining-module-passive': 'Mining Module (Passive)',
  'mining-gadget': 'Mining Gadget'
};
var categoryLabel = catLabels[row.category] || row.category || 'Mining Gear';
var name = row.name || 'Unknown';
var slug = row.slug || name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
var mfr = row.manufacturer || null;
var size = row.size ? Number(row.size) : null;


function parsePrices(raw) {
  if (!raw) return [];
  if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { return []; } }
  if (Array.isArray(raw)) return raw;
  return [];
}
function fmtPrice(v) {
  if (v === null || v === undefined) return null;
  var n = Number(v);
  if (!Number.isFinite(n) || n <= 0) return null;
  return n.toLocaleString('en-US', {minimumFractionDigits: 0, maximumFractionDigits: 0});
}
var uexPrices = parsePrices(row.uex_prices);
var datap4kPrices = parsePrices(row.datap4k_prices);
var hasUex = uexPrices.length > 0;
var hasDp4k = datap4kPrices.length > 0;

function statsToText(row) {
  if (row.category === 'mining-laser') {
    var parts = [];
    var flat = [['Filter Modifier', row.filter_modifier],['Shatter Modifier', row.shatter_modifier],['Charge Rate Modifier', row.charge_rate_modifier],['Instability Modifier', row.instability_modifier],['Window Size Modifier', row.window_size_modifier],['Catastrophic Rate Modifier', row.catastrophic_rate_modifier]];
    for (var i = 0; i < flat.length; i++) { var v = flat[i][1]; if (v === null || v === undefined) continue; var n = Number(v); if (!Number.isFinite(n)) continue; parts.push(flat[i][0] + ' ' + (n >= 0 ? '+' : '') + n + '%'); }
    return parts.length ? parts.join(', ') : null;
  } else {
    var stats = row.stats;
    if (typeof stats === 'string') { try { stats = JSON.parse(stats); } catch(e) { stats = []; } }
    if (!Array.isArray(stats) || !stats.length) return null;
    return stats.map(function(s) { return s.label + ' ' + s.value; }).join(', ');
  }
}

var statsText = statsToText(row);
var sentences = [];
var s1 = 'The ' + name + ' is a ' + (size ? 'size ' + size + ' ' : '') + categoryLabel.toLowerCase() + (mfr ? ' manufactured by ' + mfr : '') + '.';
sentences.push(s1);
if (row.category === 'mining-laser') sentences.push('Mining lasers are attached to ships or handheld mining tools to extract resources from rocks.');
else if (row.category === 'mining-module-active') sentences.push('Active modules are temporarily equipped to a mining laser to boost performance during a session.');
else if (row.category === 'mining-module-passive') sentences.push('Passive modules provide persistent stat changes when equipped to a mining laser.');
else if (row.category === 'mining-gadget') sentences.push('Mining gadgets are throwable devices used during the extraction process to affect rock properties.');
if (statsText) sentences.push((row.category === 'mining-laser' ? 'Key stats' : 'Modifiers') + ': ' + statsText + '.');
if (hasUex) {
  sentences.push('Available at ' + uexPrices.length + ' terminal' + (uexPrices.length > 1 ? 's' : '') + ' with live UEX pricing.');
} else if (hasDp4k) {
  sentences.push('Shop data available from DataPack (prices may be outdated).');
} else {
  sentences.push('No live purchase pricing is currently available in UEX.');
}
var kb_text = sentences.join(' ');

function fnv1a32Hex(str) { var hash = 0x811c9dc5; for (var i = 0; i < str.length; i++) { hash ^= str.charCodeAt(i); hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0; } return hash.toString(16).padStart(8, '0'); }
function hash16(str) { return fnv1a32Hex(str) + fnv1a32Hex(str + '|v2'); }
function stableStringify(val) { if (val === null || typeof val !== 'object') return JSON.stringify(val); if (Array.isArray(val)) return '[' + val.map(stableStringify).join(',') + ']'; var keys = Object.keys(val).sort(); return '{' + keys.map(function(k) { return JSON.stringify(k) + ':' + stableStringify(val[k]); }).join(',') + '}'; }

var entity_metadata = { category: row.category, category_label: categoryLabel, manufacturer: mfr, size: size };
var jsonkb = {
  kb_version: '1.0', entity_type: 'mining_gear', entity_id: null, entity_slug: slug, entity_name: name,
  source: 'datap4k', source_id: 'datap4k_mining_gear_norm:' + row.id, source_table: 'datap4k_mining_gear_norm',
  kb_text: kb_text,
  kb_links: { kb_page_path: '/kb/' + slug, kb_browse_path: '/browse?category=mining_gear' },
  entity_metadata: entity_metadata,
  rag_hints: { sql_hints: [], notes: null },
  provenance: { generated_at: new Date().toISOString(), kb_generator_workflow: 'JSONKB - Mining Gear v1', game_version: null, is_live_only: false, content_hash: '' }
};
var hashBasis = stableStringify({ entity_type: jsonkb.entity_type, entity_id: jsonkb.entity_id, kb_text: jsonkb.kb_text, entity_metadata: jsonkb.entity_metadata });
jsonkb.provenance.content_hash = hash16(hashBasis);
return [{ json: { item_id: row.id, slug: slug, name: name, jsonkb: jsonkb, jsonkb_file_path: '/kb/mining_gear/' + slug } }];

