const buildResult = $('Build JSONKB').item.json;
const existingRow = items[0].json;
const currentHash = buildResult.jsonkb && buildResult.jsonkb.provenance ? buildResult.jsonkb.provenance.content_hash : null;
const existingHash = existingRow ? existingRow.content_hash : null;
const should_write = !existingHash || existingHash !== currentHash;
return [{ json: Object.assign({}, buildResult, { should_write: should_write, existing_hash: existingHash }) }];
